  1	import React, { FC, FormEvent, MouseEvent, useEffect, useMemo, useState } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	import { useLocation } from 'react-router-dom-v5-compat';
  4	
  5	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  6	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
  7	import useEventListener from '@kubevirt-utils/hooks/useEventListener';
  8	import { t } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  9	import { isEmpty } from '@kubevirt-utils/utils/utils';
 10	import {
 11	  Bullseye,
 12	  Icon,
 13	  Menu,
 14	  MenuContent,
 15	  MenuItem,
 16	  MenuList,
 17	  Popper,
 18	  SearchInput,
 19	  Title,
 20	} from '@patternfly/react-core';
 21	import { SearchIcon } from '@patternfly/react-icons';
 22	
 23	import { getSearchItems, SearchItem } from '../utils/search';
 24	
 25	import { createConfigurationSearchURL } from './utils/utils';
 26	
 27	import './virtual-machine-configuration-tab-search.scss';
 28	
 29	type VirtualMachineConfigurationTabSearchProps = {
 30	  vm: V1VirtualMachine;
 31	};
 32	
 33	const VirtualMachineConfigurationTabSearch: FC<VirtualMachineConfigurationTabSearchProps> = ({
 34	  vm,
 35	}) => {
 36	  const searchItems = useMemo(() => getSearchItems(vm), [vm]);
 37	  const [value, setValue] = useState<string>('');
 38	  const navigate = useNavigate();
 39	  const location = useLocation();
 40	  const [autocompleteOptions, setAutocompleteOptions] =
 41	    useState<{ element: SearchItem; tab: string }[]>(searchItems);
 42	
 43	  const [isAutocompleteOpen, setIsAutocompleteOpen] = useState<boolean>(false);
 44	  useEventListener('click', () => setIsAutocompleteOpen(false));
 45	
 46	  const onClear = () => {
 47	    setValue('');
 48	  };
 49	
 50	  // Every click on item set and render as its pushing new url - this is for keeping the select item in search bar
 51	  useEffect(() => {
 52	    const hash = location?.hash;
 53	    const item = searchItems?.find(({ element }) => element?.id === hash.substring(1));
 54	    setValue(item?.element?.title || '');
 55	  }, [location.hash, searchItems]);
 56	
 57	  const onChange = (_e: FormEvent<HTMLInputElement>, newValue: string) => {
 58	    setIsAutocompleteOpen(true);
 59	    setValue(newValue);
 60	    const isEmptyValue = isEmpty(newValue);
 61	    const options =
 62	      !isEmptyValue &&
 63	      searchItems.reduce(
 64	        (acc, item) => {
 65	          const title = item.element.title.toLowerCase();
 66	          const match = newValue.toLowerCase();
 67	
 68	          if (item.element.isDisabled) return acc;
 69	
 70	          if (title.startsWith(match)) {
 71	            acc.startWith.push(item);
 72	            return acc;
 73	          }
 74	
 75	          if (title.includes(match)) acc.includes.push(item);
 76	
 77	          return acc;
 78	        },
 79	        { includes: [], startWith: [] },
 80	      );
 81	    const autoCompleteOptions =
 82	      options && [...options.startWith, ...options.includes].flat().slice(0, 9);
 83	    setAutocompleteOptions(isEmptyValue ? searchItems : autoCompleteOptions);
 84	  };
 85	
 86	  const onSelect = (e: MouseEvent<Element, globalThis.MouseEvent>, itemId: string) => {
 87	    e.stopPropagation();
 88	    setValue(itemId);
 89	    setIsAutocompleteOpen(false);
 90	  };
 91	
 92	  useEffect(() => {
 93	    setAutocompleteOptions(getSearchItems(vm));
 94	  }, [vm]);
 95	
 96	  return (
 97	    <Popper
 98	      popper={
 99	        <Menu isScrollable onSelect={onSelect}>
100	          <MenuContent>
101	            <MenuList>
102	              {autocompleteOptions.map(({ element, tab }) => (
103	                <MenuItem
104	                  onClick={() =>
105	                    navigate(createConfigurationSearchURL(tab, element?.id, location?.pathname))
106	                  }
107	                  description={element?.description}
108	                  itemId={element?.title}
109	                  key={element?.id}
110	                >
111	                  {element?.title}
112	                </MenuItem>
113	              ))}
114	              {isEmpty(autocompleteOptions) && (
115	                <Bullseye className="VirtualMachineConfigurationTabSearch--main__no-results">
116	                  <Icon color="grey" size="xl">
117	                    <SearchIcon />
118	                  </Icon>
119	                  <Title headingLevel="h5">
120	                    <MutedTextSpan text={t('No configurable settings found')} />
121	                  </Title>
122	                </Bullseye>
123	              )}
124	            </MenuList>
125	          </MenuContent>
126	        </Menu>
127	      }
128	      trigger={
129	        <SearchInput
130	          className="VirtualMachineConfigurationTabSearch--main"
131	          id="VirtualMachineConfigurationTabSearch-autocomplete-search"
132	          onChange={onChange}
133	          onClear={onClear}
134	          value={value}
135	        />
136	      }
137	      isVisible={isAutocompleteOpen}
138	    />
139	  );
140	};
141	
142	export default VirtualMachineConfigurationTabSearch;

